import { Injectable } from '@angular/core';
import { BehaviorSubject, filter, take, map, Observable } from 'rxjs';
import { BaseService } from '../Base/base.service';
import { Reservation } from '../../models';

export interface CreateReservationData {
  restaurant_id?: string; // Opzionale, viene ottenuto dal servizio se non fornito
  table_id?: string;
  reservation_date: string;
  reservation_time: string;
  party_size: number;
  special_requests?: string;
  // Per clienti registrati
  customer_id?: string;
  // Per clienti non registrati (obbligatori se non c'è customer_id)
  customer_name?: string;
  customer_surname?: string;
  customer_phone?: string;
  customer_email?: string;
  status?: 'pending' | 'confirmed' | 'cancelled';
  menu_id?: string; 
}


@Injectable({
  providedIn: 'root'
})
export class ReservationService extends BaseService<Reservation> {

  // ✅ Mantieni solo restaurantReservationsSubject per logica specifica
  private restaurantReservationsSubject = new BehaviorSubject<Reservation[]>([]);
  public restaurantReservations$ = this.restaurantReservationsSubject.asObservable();
  private refreshTriggerSubject = new BehaviorSubject<void>(undefined);
  public refreshTrigger$ = this.refreshTriggerSubject.asObservable();

  constructor() {
    super();

    // Carica prenotazioni cliente quando l'utente è autenticato
    this.authService.currentUser$
      .pipe(filter(u => !!u), take(1))
      .subscribe(() => {
        this.loadCustomerReservations();
      });

    // Carica prenotazioni ristorante per staff/owner
    this.loadRestaurantReservations();
  }

  // ✅ Implementa il metodo astratto richiesto da BaseService
  override getTableName(): string {
    return 'reservations';
  }

  // === METODI PER CLIENTI ===

  // Carica prenotazioni per l'utente cliente corrente
  async loadCustomerReservations(): Promise<void> {
    try {
      const user = this.authService.currentUserValue;
      if (!user) {
        console.log('No user found for customer reservations');
        this.dataSubject.next([]);
        return;
      }

      await this.loadData({ customer_id: user.id });
      console.log('Customer reservations loaded via BaseService');
      
    } catch (error) {
      console.error('Error in loadCustomerReservations:', error);
      this.handleError('loadCustomerReservations', error);
    }
  }

  // === METODI PER RISTORANTE (STAFF/OWNER) ===

  // Carica TUTTE le prenotazioni del ristorante
async loadRestaurantReservations(): Promise<void> {
  try {
    this.loadingSubject.next(true);

    const restaurantId = await this.getCurrentRestaurantId();
    
    if (!restaurantId) {
      console.log('No restaurant ID available for staff');
      this.restaurantReservationsSubject.next([]);
      this.loadingSubject.next(false);
      return;
    }

    console.log('🔍 Querying reservations for restaurant:', restaurantId);

    // ✅ CORREGGI QUESTA QUERY
    const { data: reservations, error } = await this.supabaseService.getSupabaseClient()
      .from(this.getTableName())
      .select(`
        *,
        users:users!customer_id (
          first_name,
          last_name,
          email,
          phone
        ),
        tables:tables!table_id (
          table_name,
          table_number,
          capacity
        )
      `)
      .eq('restaurant_id', restaurantId)
      .order('reservation_date', { ascending: true })
      .order('reservation_time', { ascending: true });

    if (error) {
      throw error;
    }

    console.log('✅ Restaurant reservations loaded:', reservations?.length);
    console.log('📧 Sample reservation:', reservations?.[0]);
    
    this.restaurantReservationsSubject.next(reservations || []);
    
  } catch (error) {
    console.error('Error loading restaurant reservations:', error);
    this.handleError('loadRestaurantReservations', error);
  } finally {
    this.loadingSubject.next(false);
  }
}


  // Crea una nuova prenotazione come cliente
async createCustomerReservation(reservationData: CreateReservationData): Promise<Reservation | null> {
  try {
    const user = this.authService.currentUserValue;
    if (!user) {
      throw new Error('User not authenticated');
    }

    // Per cliente registrato, customer_id è obbligatorio (viene dall'utente loggato)
    const reservationToCreate = {
      restaurant_id: reservationData.restaurant_id,
      customer_id: user.id, // Prende l'ID dall'utente loggato
      table_id: reservationData.table_id,
      reservation_date: reservationData.reservation_date,
      reservation_time: reservationData.reservation_time,
      party_size: reservationData.party_size,
      special_requests: reservationData.special_requests,
      status: 'pending' as const
    };

    const result = await this.create(reservationToCreate);
    
    if (result) {
      await this.loadCustomerReservations();
      await this.loadRestaurantReservations();
    }
    
    return result;
  } catch (error) {
    console.error('❌ Error creating customer reservation:', error);
    this.handleError('createCustomerReservation', error);
    return null;
  }
}

  // Crea una prenotazione come ristorante
async createRestaurantReservation(data: CreateReservationData): Promise<Reservation | null> {
  try {
    // Ottieni restaurant_id
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) {
      throw new Error('Nessun ristorante selezionato');
    }

    const reservationData = {
      ...data,
      restaurant_id: restaurantId,
      customer_id: data.customer_id || null,
      table_id: data.table_id || null,
      menu_id: data.menu_id || null, // <-- Assicurati che sia incluso
      status: data.status || 'confirmed',
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    };

    console.log('📤 Creazione prenotazione con menu_id:', reservationData.menu_id);

    const { data: result, error } = await this.supabaseService.getSupabaseClient()
      .from('reservations')
      .insert(reservationData)
      .select(`
        *,
        tables (
          table_name,
          table_number,
          capacity
        ),
        menus (
          id,
          name,
          is_default,
          is_active
        )
      `)
      .single();

    if (error) throw error;

    // Aggiorna la cache delle prenotazioni
    await this.loadRestaurantReservations();

    return result;
  } catch (error) {
    console.error('Error creating restaurant reservation:', error);
    return null;
  }
}


  // === METODI GESTIONE PRENOTAZIONI ===
async updateReservation(reservationId: string, updates: Partial<Reservation>): Promise<boolean> {
  try {
    console.log('🔧 Aggiornamento prenotazione:', {
      reservationId,
      updates
    });

    // Filtra solo i campi che esistono nella tabella reservations
    const validUpdates: any = {};
    
    // Lista dei campi validi nella tabella reservations
    const validFields = [
      'customer_name',
      'customer_surname',
      'customer_phone',
      'customer_email',
      'reservation_date',
      'reservation_time',
      'party_size',
      'special_requests',
      'table_id',
      'status',
      'menu_id',
      'updated_at'
    ];

    // Copia solo i campi validi
    Object.keys(updates).forEach(key => {
      if (validFields.includes(key) && updates[key as keyof Reservation] !== undefined) {
        const value = updates[key as keyof Reservation];
        
        // Gestione speciale per menu_id: converte "null" in null
        if (key === 'menu_id') {
          if (value === 'null' || value === '') {
            validUpdates[key] = null;
          } else {
            validUpdates[key] = value;
          }
        } else {
          validUpdates[key] = value;
        }
      }
    });

    // Aggiungi updated_at
    validUpdates.updated_at = new Date().toISOString();

    console.log('📤 Dati validi per l\'aggiornamento:', validUpdates);

    const { error } = await this.supabaseService.getSupabaseClient()
      .from('reservations')
      .update(validUpdates)
      .eq('id', reservationId);

    if (error) {
      console.error('❌ Errore Supabase:', error);
      console.error('❌ Dettagli:', error.details);
      console.error('❌ Hint:', error.hint);
      console.error('❌ Messaggio:', error.message);
      throw error;
    }

    console.log('✅ Prenotazione aggiornata con successo');
    return true;
  } catch (error) {
    console.error('❌ Errore aggiornamento prenotazione:', error);
    return false;
  }
}


async updateReservationStatus(reservationId: string, status: 'pending' | 'confirmed' | 'cancelled'): Promise<boolean> {
  // Ora usa il metodo generico updateReservation
  return await this.updateReservation(reservationId, { status });
}

async assignTableToReservation(reservationId: string, tableId: string): Promise<boolean> {
  const result = await this.update(reservationId, { table_id: tableId });
  
  if (result) {
    await this.loadRestaurantReservations();
    this.triggerRefresh(); // ← Aggiungi questa linea
  }
  
  return result;
}

async removeTableFromReservation(reservationId: string): Promise<boolean> {
  const result = await this.update(reservationId, { table_id: null });
  
  if (result) {
    await this.loadRestaurantReservations();
    this.triggerRefresh(); // ← Aggiungi questa linea
  }
  
  return result;
}

async deleteReservation(reservationId: string): Promise<boolean> {
  const result = await super.delete(reservationId);
  
  if (result) {
    // Ricarica i dati
    await this.loadRestaurantReservations();
    // Trigger per notificare gli altri servizi
    this.triggerRefresh();
  }
  
  return result;
}

triggerRefresh(): void {
  this.refreshTriggerSubject.next(undefined);
}


  // === METODI DI UTILITY ===
  getFutureReservations(reservations: Reservation[]): Reservation[] {
    const today = new Date().toISOString().split('T')[0];
    return reservations.filter(reservation => 
      reservation.reservation_date >= today &&
      ['pending', 'confirmed'].includes(reservation.status)
    );
  }

  getReservationsByDate(reservations: Reservation[], date: string): Reservation[] {
    return reservations.filter(reservation => 
      reservation.reservation_date === date
    );
  }

  getActiveReservations(reservations: Reservation[]): Reservation[] {
    const today = new Date().toISOString().split('T')[0];
    return reservations.filter(reservation => 
      reservation.reservation_date === today &&
      ['pending', 'confirmed'].includes(reservation.status)
    );
  }

getCustomerName(reservation: Reservation): string {
  // 1. Se ha relazione users (cliente registrato)
  if (reservation.users) {
    return `${reservation.users.first_name || ''} ${reservation.users.last_name || ''}`.trim();
  }
  
  // 2. Se ha customer_name (cliente non registrato)
  if (reservation.customer_name) {
    return reservation.customer_name;
  }
  
  return 'Cliente';
}

getCustomerContact(reservation: Reservation): string {
  // 1. Cliente registrato
  if (reservation.users) {
    return reservation.users.phone || reservation.users.email || '';
  }
  
  // 2. Cliente non registrato
  return reservation.customer_phone || reservation.customer_email || '';
}

  getTableInfo(reservation: Reservation): string {
    if (reservation.tables) {
      return `${reservation.tables.table_name} (${reservation.tables.table_number})`;
    }
    return 'N/A';
  }

  // Observable per prenotazioni future del ristorante
  getRestaurantFutureReservations$(): Observable<Reservation[]> {
    return this.restaurantReservations$.pipe(
      map(reservations => this.getFutureReservations(reservations))
    );
  }

  // Observable per prenotazioni odierne del ristorante
  getRestaurantTodayReservations$(): Observable<Reservation[]> {
    return this.restaurantReservations$.pipe(
      map(reservations => this.getActiveReservations(reservations))
    );
  }

  // ✅ Override del clearCache
override clearCache(): void {
  super.clearCache();
  
  // Usa setTimeout per evitare il problema di timing
  setTimeout(() => {
    if (this.restaurantReservationsSubject) {
      this.restaurantReservationsSubject.next([]);
    }
  }, 0);
}


  // === METODI DISPONIBILITÀ - AGGIUNGI QUESTI ===

  async checkTableAvailability(tableId: string, date: string, time: string): Promise<boolean> {
    try {
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('reservations')
        .select('id')
        .eq('table_id', tableId)
        .eq('reservation_date', date)
        .eq('reservation_time', time)
        .in('status', ['pending', 'confirmed'])
        .limit(1);

      if (error) throw error;

      return !data || data.length === 0;
    } catch (error) {
      console.error('❌ Error checking table availability:', error);
      return false;
    }
  }

  async getAvailableTimes(tableId: string, date: string): Promise<string[]> {
    try {
      const openingHours = [
        '12:00', '12:30', '13:00', '13:30', '14:00',
        '19:00', '19:30', '20:00', '20:30', '21:00', '21:30'
      ];

      const { data: existingReservations, error } = await this.supabaseService.getSupabaseClient()
        .from('reservations')
        .select('reservation_time')
        .eq('table_id', tableId)
        .eq('reservation_date', date)
        .in('status', ['pending', 'confirmed']);

      if (error) throw error;

      const bookedTimes = existingReservations?.map(r => r.reservation_time) || [];
      return openingHours.filter(time => !bookedTimes.includes(time));
    } catch (error) {
      console.error('❌ Error getting available times:', error);
      return [];
    }
  }

// Menù Specifico per prenotazione
async getReservationWithMenu(reservationId: string): Promise<Reservation | null> {
  try {
    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from('reservations')
      .select(`
        *,
        menus (*)
      `)
      .eq('id', reservationId)
      .single();

    if (error) throw error;
    return data;
  } catch (error) {
    console.error('Error fetching reservation with menu:', error);
    return null;
  }
}

async updateReservationMenu(reservationId: string, menuId: string | null): Promise<boolean> {
  try {
    const { error } = await this.supabaseService.getSupabaseClient()
      .from('reservations')
      .update({ 
        menu_id: menuId,
        updated_at: new Date().toISOString()
      })
      .eq('id', reservationId);

    if (error) throw error;
    return true;
  } catch (error) {
    console.error('Error updating reservation menu:', error);
    return false;
  }
}



}